/* 1. Reading progress bar */
(function(){const a=document.querySelector("article");if(!a)return;const b=document.createElement("div");b.id="reading-progress";b.style.width="0%";b.setAttribute("aria-hidden","true");document.body.appendChild(b);window.addEventListener("scroll",()=>{const r=a.getBoundingClientRect(),t=a.offsetHeight-window.innerHeight;if(t>0)b.style.width=Math.min(Math.max(-r.top/t,0),1)*100+"%"},{passive:true})})();
/* 2. ToC scroll-spy */
(function(){const tl=document.querySelectorAll('.toc-list a[href^="#"]');if(!tl.length)return;const ids=[];tl.forEach(a=>ids.push(a.getAttribute("href").slice(1)));const h=ids.map(id=>document.getElementById(id)).filter(Boolean);if(!h.length)return;const o=new IntersectionObserver(es=>{es.forEach(e=>{const l=document.querySelector('.toc-list a[href="#'+e.target.id+'"]');if(l&&e.isIntersecting){tl.forEach(a=>a.classList.remove("toc-active"));l.classList.add("toc-active")}})},{rootMargin:"-80px 0px -70% 0px",threshold:0});h.forEach(el=>o.observe(el))})();
/* 3. Mobile menu toggle + Escape key */
(function(){const t=document.getElementById("menu-toggle");if(!t)return;const m=document.getElementById("mobile-menu"),o=document.querySelector(".menu-open"),c=document.querySelector(".menu-close");t.addEventListener("click",()=>{const h=m.classList.contains("hidden");m.classList.toggle("hidden");o.classList.toggle("hidden",h);c.classList.toggle("hidden",!h);t.setAttribute("aria-expanded",String(h))});document.addEventListener("keydown",e=>{if(e.key==="Escape"&&m&&!m.classList.contains("hidden")){m.classList.add("hidden");o.classList.remove("hidden");c.classList.add("hidden");t.setAttribute("aria-expanded","false");t.focus()}})})();
/* 4. Language switcher dropdown */
(function(){function init(v){const sfx=v?"-"+v:"",s=document.getElementById("lang-switcher"+sfx);if(!s)return;const b=document.getElementById("lang-toggle"+sfx),m=document.getElementById("lang-menu"+sfx);b.addEventListener("click",e=>{e.stopPropagation();const h=m.classList.contains("hidden");m.classList.toggle("hidden");b.setAttribute("aria-expanded",String(h))});document.addEventListener("click",e=>{if(!s.contains(e.target)){m.classList.add("hidden");b.setAttribute("aria-expanded","false")}});document.addEventListener("keydown",e=>{if(e.key==="Escape"&&!m.classList.contains("hidden")){m.classList.add("hidden");b.setAttribute("aria-expanded","false");b.focus()}})}init("desktop");init("mobile")})();
/* 5. Code copy buttons */
(function(){const c=document.getElementById("sayfa-code-copy");if(!c)return;const sel=c.dataset.selector||"pre code",ct=c.dataset.copyText||"Copy",cd=c.dataset.copiedText||"Copied!";document.querySelectorAll(sel).forEach(block=>{const pre=block.parentNode;if(pre.parentNode.classList.contains("code-block-wrap"))return;const lang=block.className.replace(/^language-/,"")||"";const w=document.createElement("div");w.className="code-block-wrap not-prose";const h=document.createElement("div");h.className="code-block-header";h.innerHTML='<span class="code-block-lang">'+lang+'</span><button class="copy-btn code-copy-btn"><svg class="code-copy-icon icon-copy" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24" aria-hidden="true"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg><svg class="code-copy-icon icon-check" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24" aria-hidden="true"><path d="M20 6 9 17l-5-5"/></svg><span class="copy-label">'+ct+"</span></button>";const btn=h.querySelector(".copy-btn");btn.addEventListener("click",()=>{const code=btn.closest(".code-block-wrap").querySelector("code").textContent;navigator.clipboard.writeText(code).then(()=>{btn.classList.add("copied");btn.querySelector(".copy-label").textContent=cd;setTimeout(()=>{btn.classList.remove("copied");btn.querySelector(".copy-label").textContent=ct},2000)}).catch(()=>{})});pre.style.margin="0";pre.className="code-block-pre";const p=pre.parentNode;p.insertBefore(w,pre);w.appendChild(h);w.appendChild(pre)})})();
/* 6. Copy link buttons */
(function(){document.addEventListener("click",e=>{const b=e.target.closest('[data-action="copy-link"]');if(!b)return;const s=b.querySelector("span");if(!s)return;const ct=b.dataset.copyText,cd=b.dataset.copiedText;navigator.clipboard.writeText(window.location.href).then(()=>{s.textContent=cd;setTimeout(()=>{s.textContent=ct},2000)}).catch(()=>{})})})();
